const sampleData = {
  users: [
    { name: 'Alice Johnson', email: 'alice@example.com', age: 30, joinDate: '2024-01-15', skills: ['JavaScript', 'Python', 'SQL'] },
    { name: 'Bob Smith', email: 'bob@example.com', age: 25, joinDate: '2024-03-22', skills: ['React', 'TypeScript'] },
    { name: 'Carol Williams', email: 'carol@example.com', age: 35, joinDate: '2023-11-08', skills: ['Python', 'ML', 'Data Science'] }
  ],
  products: [
    { name: 'Widget A', price: 29.99, category: 'tools', stock: 150 },
    { name: 'Widget B', price: 49.99, category: 'tools', stock: 75 },
    { name: 'Gadget X', price: 99.99, category: 'electronics', stock: 30 }
  ],
  rawText: 'Hello World! This is a sample text with MIXED casing and   extra    spaces.'
};

return { sampleData, focusArea: $.input.focusArea || 'all' };

const data = $.steps.generateSampleData.output.sampleData;
const focus = $.steps.generateSampleData.output.focusArea;
const examples = [];

if (focus === 'all' || focus === 'strings') {
  examples.push({ category: 'String Operations', name: 'Lowercase', input: data.rawText, code: 'text.toLowerCase()', output: data.rawText.toLowerCase() });
  examples.push({ category: 'String Operations', name: 'Trim extra spaces', input: data.rawText, code: 'text.replace(/\\s+/g, " ").trim()', output: data.rawText.replace(/\s+/g, ' ').trim() });
  examples.push({ category: 'String Operations', name: 'Extract domain from email', input: data.users[0].email, code: 'email.split("@")[1]', output: data.users[0].email.split('@')[1] });
  examples.push({ category: 'String Operations', name: 'Title case', input: 'hello world', code: 'str.split(" ").map(w => w[0].toUpperCase() + w.slice(1)).join(" ")', output: 'Hello World' });
}

if (focus === 'all' || focus === 'arrays') {
  const allSkills = data.users.flatMap(u => u.skills);
  const uniqueSkills = [...new Set(allSkills)];
  examples.push({ category: 'Array Operations', name: 'Flatten + unique skills', input: 'users[].skills', code: '[...new Set(users.flatMap(u => u.skills))]', output: uniqueSkills.join(', ') });
  examples.push({ category: 'Array Operations', name: 'Filter by age > 28', input: 'users[]', code: 'users.filter(u => u.age > 28).map(u => u.name)', output: data.users.filter(u => u.age > 28).map(u => u.name).join(', ') });
  examples.push({ category: 'Array Operations', name: 'Sort products by price', input: 'products[]', code: 'products.sort((a,b) => b.price - a.price).map(p => p.name)', output: [...data.products].sort((a, b) => b.price - a.price).map(p => p.name).join(', ') });
  const totalStock = data.products.reduce((sum, p) => sum + p.stock, 0);
  examples.push({ category: 'Array Operations', name: 'Sum stock with reduce', input: 'products[].stock', code: 'products.reduce((sum, p) => sum + p.stock, 0)', output: String(totalStock) });
}

if (focus === 'all' || focus === 'dates') {
  const now = new Date();
  examples.push({ category: 'Date Operations', name: 'Format ISO to readable', input: '2024-01-15', code: 'new Date(d).toLocaleDateString("en-US", {weekday: "long", year: "numeric", month: "long", day: "numeric"})', output: new Date('2024-01-15').toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' }) });
  examples.push({ category: 'Date Operations', name: 'Days since join', input: data.users[0].joinDate, code: 'Math.floor((Date.now() - new Date(d)) / 86400000)', output: String(Math.floor((Date.now() - new Date(data.users[0].joinDate)) / 86400000)) + ' days' });
}

if (focus === 'all' || focus === 'objects') {
  const grouped = {};
  data.products.forEach(p => { if (!grouped[p.category]) grouped[p.category] = []; grouped[p.category].push(p.name); });
  examples.push({ category: 'Object Operations', name: 'Group products by category', input: 'products[]', code: 'products.reduce into grouped object', output: JSON.stringify(grouped) });
  examples.push({ category: 'Object Operations', name: 'Pick specific fields', input: 'user object', code: '({ name, email } = user)', output: JSON.stringify({ name: data.users[0].name, email: data.users[0].email }) });
}

if (focus === 'all' || focus === 'math') {
  const avg = data.products.reduce((s, p) => s + p.price, 0) / data.products.length;
  examples.push({ category: 'Math Operations', name: 'Average price', input: 'products[].price', code: 'arr.reduce((s,p) => s + p.price, 0) / arr.length', output: '$' + avg.toFixed(2) });
  const max = Math.max(...data.products.map(p => p.price));
  examples.push({ category: 'Math Operations', name: 'Max price', input: 'products[].price', code: 'Math.max(...products.map(p => p.price))', output: '$' + max.toFixed(2) });
}

return { examples, totalExamples: examples.length };

const examples = $.steps.runTransformations.output.examples || [];
const focus = $.steps.generateSampleData.output.focusArea;

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Data Transformation Reference Guide' } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Focus:* ' + focus + ' | *Examples:* ' + examples.length } });
blocks.push({ type: 'divider' });

let currentCategory = '';
examples.forEach((ex, i) => {
  if (ex.category !== currentCategory) {
    currentCategory = ex.category;
    blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*:bookmark: ' + currentCategory + '*' } });
  }

  let exText = '*' + ex.name + '*\n';
  exText += '```' + ex.code + '```\n';
  exText += ':arrow_right: Result: `' + String(ex.output).slice(0, 200) + '`';

  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: exText.slice(0, 1800) } });
});

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Data Transformation Tutorial | Powered by One CLI code steps' }] });

const fallback = 'Data transformation guide: ' + examples.length + ' examples';
return { blocks, fallback };
